<?php

namespace App\View\Components;

use Closure;
use Illuminate\Contracts\View\View;
use Illuminate\Support\Str;
use Illuminate\View\Component;

class EditorjsRenderer extends Component
{
    public function __construct(
        public ?array $content = null,
    ) {}

    public function render(): View|Closure|string
    {
        return view('components.editorjs-renderer', [
            'blocks' => $this->content['blocks'] ?? [],
        ]);
    }

    public static function renderListItems(array $items = [], string $tag = 'ul'): string
    {
        return collect($items)
            ->map(function ($item) use ($tag): string {
                if (is_string($item)) {
                    return '<li>' . $item . '</li>';
                }

                if (! is_array($item)) {
                    return '';
                }

                $content = $item['content'] ?? '';
                $children = filled($item['items'] ?? null)
                    ? self::renderListItems($item['items'], $tag)
                    : '';

                return '<li>' . $content . $children . '</li>';
            })
            ->implode('');
    }

    public static function headingId(string $text): string
    {
        return Str::slug(trim(html_entity_decode(strip_tags($text)))) ?: 'section';
    }

